-- Step 1: Disable Row Level Security and grant full access to allow Admin Panel updates
ALTER TABLE public.medicines DISABLE ROW LEVEL SECURITY;
GRANT ALL ON public.medicines TO anon, authenticated, service_role;

-- Step 2: Clear existing medicines table
TRUNCATE TABLE public.medicines;

